def combination_sum4(nums, target):
    def helper(remaining):
        if remaining == 0:
            return 1
        if remaining < 0:
            return 0
        total = 0
        for x in nums:
            total += helper(remaining - x)
        return total

    return helper(target)

def combination_sum4(nums, target):
    dp = [0] * (target + 1)
    dp[0] = 1
    for t in range(1, target + 1):
        for x in nums:
            if x <= t:
                dp[t] += dp[t - x]
    return dp[target]
